    49→  export function UpsertStateMetadata(params: {
    50→    operation: UpsertMetadataOperation;
    51→    userID: MachineUserID;
    52→    mappedSlices: Slices.SlicesMap;
    53→    currentSessionID: string;
    54→  }) {
    55→    const { operation, userID, mappedSlices, currentSessionID } = params;
    56→
    57→    if (operation.op === 'update') {
    58→      const { originActionType, state, override } = operation;
    59→      const previousMetadata = state[METADATA_FIELD_NAME] as MachineMetadata;
    60→
    61→      assertObject(
    62→        previousMetadata,
    63→        'UpsertStateMetadata failed. No metadata found in state.',
    64→      );
    65→
    66→      const meta = {
    67→        /** NOT updated fields, used for cache invalidation **/
    68→        userID: previousMetadata.userID, // not updated, used by cache strategy
    69→        startedAt: previousMetadata.startedAt, // not updated, used by cache strategy
    70→        slicesCacheStrategy: previousMetadata.slicesCacheStrategy, // not updated, used by cache strategy
    71→        sessionID: previousMetadata.sessionID, // not updated, used by cache strategy
    72→        /** Updated fields **/
    73→        updatedByActionType: originActionType,
    74→        changes: previousMetadata.changes + 1,
    75→        updatedAt: Date.now(),
    76→        ...override,
    77→      } satisfies MachineMetadata;
    78→
    79→      return {
