import type {
  AnyFunction,
  AsString,
  Cast,
  Compute,
  ComputeAny,
  PromiseValue,
  Serializable,
  SerializableOnly,
  UnionToIntersection,
  Writable,
} from '../../helpers/type-utils';
import type { CacheStrategy } from './cache';
import type {
  MachineAction,
  MachineStoreMiddlewareAPI,
  METADATA_FIELD_NAME,
} from './machine';
import type { AsyncSlice, Slice, SliceKind } from './slice';

/**
 * Represents the runtime context, which can contain serializable data
 * or functions (e.g., an API client).
 */
export type SliceContext = {
  [K: string]: Serializable | AnyFunction | SliceContext;
} & { userID?: MachineUserID };

/** Represents the shape of a slice's state. */
export type MachineState = { [K: string]: unknown };

/**
 * A proxy of the state passed to reducers (via Immer).
 * It allows for direct, "mutable" syntax for state updates.
 */
export type WritableStateProxy<State> = Writable<SerializableOnly<State>>;

export type MachineReducer<State = MachineState, Action = MachineAction> = (
  state: Readonly<State>,
  action: Action,
) => State;

export type SliceReducer<State = MachineState, Payload = unknown> = (
  state: WritableStateProxy<State>,
  payload: Payload,
) => void;

/**
 * @internal
 * Extracts the return types of all selector functions.
 */
export type ExtractSelectorValues<Selectors> = {
  [K in keyof Selectors]: Selectors[K] extends (s: any) => infer R ? R : never;
};

export type MachineUserID = string | number | null | undefined;

/**
 * Internal Machine metadata
 */
export type MachineMetadata = {
  userID: MachineUserID; // used to handle the cache policy
  updatedAt: number; // timestamp from last machine state change
  startedAt: number; // defined at the first rootReducer iteration
  updatedByActionType: string; // last action type that updated state
  changes: number; // changes count
  sessionID: string;
  slicesCacheStrategy: {
    [K: string]: CacheStrategy | undefined; // the cache strategy used for each slice
  };
};

export type WithMetadata<State> = State & {
  [L in METADATA_FIELD_NAME]: MachineMetadata;
};

export type WithMetadataParam<State> = State & {
  [L in METADATA_FIELD_NAME]?: MachineMetadata;
};

export type MachineMiddleware = (
  api: MachineStoreMiddlewareAPI,
) => (
  next: (action: UnknownAction) => UnknownAction,
) => (action: UnknownAction) => any;

/**
 * Utility type that merges the contexts from all slices in a machine
 * into a single, unified context type.
 */
export type CombineSlicesContext<Slices> = Compute<
  UnionToIntersection<
    {
      -readonly [K in keyof Slices]: Slices[K] extends { context: infer C }
        ? C
        : never;
    }[keyof Slices]
  >
>;

/**
 * Utility type that combines the initial states of all slices into a single
 * global state object for the machine.
 */
export type CombineSlicesState<Slices> = Cast<
  Compute<
    UnionToIntersection<{
      -readonly [K in keyof Slices]: Slices[K] extends { initial: infer I }
        ? I
        : never;
    }>
  >,
  MachineState
>;

/** A record of slice definitions. */
export type MachineSlices = { [K: string]: AnyMachineSlice };

/** A record of selector functions. */
export type MachineSelectors<State> = {
  [K: string]: (state: State) => unknown;
};

export type AnySyncSlice = ComputeAny<
  Slice<any, any, any> & { kind: SliceKind.sync }
>;
export type AnyAsyncSlice = ComputeAny<
  AsyncSlice<any, any, any, any> & { kind: SliceKind.async }
>;
export type AnyMachineSlice = Omit<
  AnySyncSlice | AnyAsyncSlice,
  'context' | 'cache'
> & {
  context?: SliceContext;
  cache: CacheStrategy;
};

/**
 * Infers the complete state shape of a machine, including the
 * return values of its selectors.
 */
export type InferMachineState<MachineConfig> = MachineConfig extends {
  readonly config: {
    slices: infer Slices extends MachineSlices;
    selectors?: infer Selectors;
  };
}
  ? WithSelectorsState<CombineSlicesState<Slices>, Selectors>
  : never;

/**
 * Extract types from all machine custom selectors config.
 */
export type WithSelectorsState<State, Selectors> = Compute<
  State & {
    +readonly [K in keyof Selectors]: Selectors[K] extends (
      ...args: any
    ) => infer R
      ? R
      : never;
  },
  'flat'
>;

export type UnknownAction = { type: string } & { [K: string]: unknown };

export type AsyncSliceError = {
  error: string;
  stack: string;
};

export type AsyncSliceActions<Payload = any, Result = any, Context = any> = {
  load(payload: Payload, context: Context): MachineAction<Payload>;
  fail(payload: AsyncSliceError): MachineAction<AsyncSliceError>;
  success(data: PromiseValue<Result>): MachineAction<Result>;
  clear(): MachineAction<Payload>;
};

/**
 * Maps a slice definition to its corresponding action creators.
 */
export type SliceToActionCreators<Slice> =
  // Async slice case
  Slice extends {
    load(payload: infer Payload, context: any): infer Result;
  }
    ? {
        load(payload: Payload): MachineAction<Payload>;
        fail(payload: AsyncSliceError): MachineAction<AsyncSliceError>;
        success(data: PromiseValue<Result>): MachineAction<Result>;
        clear(): MachineAction<Payload>;
      }
    : // Sync slice case
      Slice extends { reducers: infer Reducers }
      ? Writable<{
          [K in keyof Reducers]: Reducers[K] extends unknown
            ? Reducers[K] extends (
                state: any,
                ...args: [infer Payload] & { length: 1 }
              ) => any
              ? (payload: Payload) => MachineAction<Payload>
              : () => MachineAction<void>
            : never;
        }>
      : never;

/**
 * Maps a slice definition to its corresponding action type strings.
 * The format is `@<MachineID>/<SliceID>/<ActionName>`.
 */
export type SliceToActionTypes<
  MachineID extends string,
  Slice,
> = Slice extends {
  // Async slice case
  id: infer ID extends string;
  load(...args: any): any;
}
  ? {
      load: `@${MachineID}/${ID}/load`;
      fail: `@${MachineID}/${ID}/fail`;
      success: `@${MachineID}/${ID}/success`;
      clear: `@${MachineID}/${ID}/clear`;
    }
  : // Sync slice case
    Slice extends AnySyncSlice
    ? {
        -readonly [K in keyof Slice['reducers']]: `@${MachineID}/${Slice['id']}/${AsString<K>}`;
      }
    : never;

/**
 * Used for semantic indicating what each string type represent
 */
export namespace StringTypes {
  export type SliceReducerName = string & { '~kind': 'SliceReducerName' };

  export type SliceKey = string & { '~kind': 'SliceKey' };

  export type ActionType = string & { '~kind': 'ActionType' };
}

import type { MSTimeString } from '../../helpers/ms';

/**
 * Defines the cache invalidation policy and scope.
 */
export enum CachePolicy {
  /**
   * Public, shared cache. Invalidated only by its TTL.
   * Ideal for global data that rarely changes.
   * E.g., Plan prices, feature flag configurations.
   */
  public = 'public',

  /**
   * Private cache, bound to the user session.
   * Invalidated on logout/login OR when TTL expires.
   * E.g., User profile data, permissions.
   */
  private = 'private',

  /**
   * App session cache. Persists while the app is active.
   * Invalidated on app close/reopen OR when TTL expires.
   * E.g., Data for a specific screen that doesn't need to persist.
   */
  session = 'session',
}

/**
 * Defines the caching behavior for a slice.
 */
export type CacheStrategy = {
  /**
   * Policy defining the cache's lifecycle and scope.
   * Cache is invalidated by the policy's event OR TTL expiry, whichever comes first.
   * @default 'private'
   */
  policy: keyof typeof CachePolicy;
  /**
   * Time-To-Live (TTL). Maximum cache lifespan (e.g., '1h', '30m').
   * A TTL of 0 means the cache expires immediately, forcing revalidation.
   */
  ttl?: MSTimeString;
  /**
   * Stale-While-Revalidate (SWR).
   * If true, returns cached data (even if stale) while revalidating in the background.
   * If false and the cache is invalid, it will wait for the fresh data fetch.
   * @default true
   */
  swr?: boolean;
};

export type CacheStrategyField = keyof CacheStrategy & {};

