import { assertObject } from '../helpers/object-utils';
import { createSchema } from '../schema';
import type { SliceContext } from './models';

/** Skip validation in production for performance */
const IS_PRODUCTION = process.env.NODE_ENV === 'production';

export namespace Context {
  export const Model = createSchema({
    userID: {
      union: [
        'string',
        'number',
        'null',
        'undefined',
      ],
    },
  });

  export function Assert(value: unknown): asserts value is SliceContext {
    if (Model.isValid(value) && 'userID' in value) return;
    throw new Error(`Invalid value received for context.`);
  }

  export function Handler(slicesContext: SliceContext) {
    let current = slicesContext;

    const check = (value: unknown): SliceContext => {
      if (IS_PRODUCTION) {
        return value as SliceContext;
      }
      assertObject(value, `Expected value to be an object.`);
      Assert(value);
      return value;
    };

    return {
      get() {
        return check(current);
      },
      assign(value: Partial<SliceContext>) {
        current = check({
          ...current,
          ...value,
        });
      },
    };
  }
}

