     1→import React from 'react';
     2→
     3→import { getProperty } from '../helpers/object-utils';
     4→
     5→import type { SliceContext, StringTypes, UnknownAction } from './models';
     6→import type { Slices } from './slice';
     7→import type { Store } from './store';
     8→
     9→export function Hooks(params: {
    10→  machineID: string;
    11→  store: Store.Instance;
    12→  getContext(): SliceContext;
    13→  mappedSlices: Slices.SlicesMap;
    14→}) {
    15→  const { store, getContext, mappedSlices } = params;
    16→
    17→  function useSelector<T>(selector: (state: any) => T): T {
    18→    return React.useSyncExternalStore(store.subscribe, () => {
    19→      const fullState = store.getState();
    20→      return selector(fullState);
    21→    });
    22→  }
    23→
    24→  // transforming action creators into action dispatchers
    25→  const runtimeActions = {} as {
    26→    [K: StringTypes.SliceKey]: {
    27→      [K: StringTypes.SliceReducerName]: (payload: unknown) => UnknownAction;
    28→    };
    29→  };
    30→
    31→  mappedSlices.info.forEach(({ sliceKey }) => {
    32→    const actions = mappedSlices.actionCreatorListBySliceKey[sliceKey];
    33→    if (!actions) return;
    34→    actions.forEach(actionCreator => {
    35→      runtimeActions[sliceKey] = runtimeActions[sliceKey] || {};
    36→      runtimeActions[sliceKey][actionCreator.sliceReducerName] = (
    37→        payload: unknown,
    38→      ) => {
    39→        const context = getContext();
    40→        const actionObject = actionCreator(payload, context);
    41→        return store.dispatch(actionObject);
    42→      };
    43→    });
    44→  });
    45→
    46→  /**
    47→   * Custom React hook to interact with a specific slice of the state machine.
    48→   * Returns plain object { state, actions }.
    49→   *
    50→   * @param path The key of the slice or selector to access.
    51→   * @returns The slice's state and associated actions
    52→   */
    53→  function useMachine(path: string) {
    54→    const isSliceKey = Boolean(
    55→      mappedSlices.reducerBySliceKey[path as StringTypes.SliceKey],
    56→    );
    57→
    58→    const actionsRef = React.useRef(
    59→      isSliceKey ? runtimeActions[path as StringTypes.SliceKey] : undefined,
    60→    );
    61→
    62→    const stateRef = React.useRef<unknown>(null);
    63→
    64→    // Memoized result object to avoid creating new objects on every render
    65→    // Critical to prevent GC thrashing
    66→    const resultRef = React.useRef<{
    67→      state: unknown;
    68→      actions: unknown;
    69→    } | null>(null);
    70→
    71→    return useSelector(state => {
    72→      const selection = getProperty(state, path, true);
    73→
    74→      if (selection !== stateRef.current) {
    75→        stateRef.current = selection;
    76→        // Only create new result object when state actually changes
    77→        if (isSliceKey) {
    78→          resultRef.current = {
    79→            state: stateRef.current,
    80→            actions: actionsRef.current,
    81→          };
    82→        }
    83→      }
    84→
    85→      return isSliceKey ? resultRef.current : stateRef.current;
    86→    });
    87→  }
    88→
    89→  return {
    90→    useSelector,
    91→    useMachine,
    92→  };
    93→}
